using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

public class EvaluationResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public IReadOnlyList<CategoryMetric> PerCategory { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly object _lock = new();
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _categoryLabels;

    public bool IsTrained => _predictionEngine is not null;

    public TicketModelService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 0);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void Train()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        var model = pipeline.Fit(dataView);

        _mlContext.Model.Save(model, dataView.Schema, _modelPath);

        lock (_lock)
        {
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);

            // Extract the ordered category labels from the Label key column
            var labelColumn = dataView.Schema["Category"];
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();

            // Re-transform to get the label mapping
            var transformedData = model.Transform(dataView);
            var labelCol = transformedData.Schema["Label"];
            labelCol.GetKeyValues(ref slotNames);
            _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        }
    }

    public EvaluationResponse Evaluate()
    {
        if (!File.Exists(_modelPath))
            throw new InvalidOperationException("Model has not been trained yet. Call POST /api/tickets/train first.");

        var model = _mlContext.Model.Load(_modelPath, out _);
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var predictions = model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var perCategory = new List<CategoryMetric>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            string label = _categoryLabels is not null && i < _categoryLabels.Length
                ? _categoryLabels[i]
                : $"Class {i}";

            var confusionMatrix = metrics.ConfusionMatrix;
            double precision = confusionMatrix.PerClassPrecision.Count > i ? confusionMatrix.PerClassPrecision[i] : 0;
            double recall = confusionMatrix.PerClassRecall.Count > i ? confusionMatrix.PerClassRecall[i] : 0;
            double f1 = (precision + recall) > 0 ? 2 * precision * recall / (precision + recall) : 0;

            perCategory.Add(new CategoryMetric
            {
                Category = label,
                Precision = Math.Round(precision, 4),
                Recall = Math.Round(recall, 4),
                F1Score = Math.Round(f1, 4)
            });
        }

        return new EvaluationResponse
        {
            MacroAccuracy = Math.Round(metrics.MacroAccuracy, 4),
            MicroAccuracy = Math.Round(metrics.MicroAccuracy, 4),
            LogLoss = Math.Round(metrics.LogLoss, 4),
            LogLossReduction = Math.Round(metrics.LogLossReduction, 4),
            PerCategory = perCategory
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null || _categoryLabels is null)
                throw new InvalidOperationException("Model has not been trained yet. Call POST /api/tickets/train first.");

            var input = new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            };

            var prediction = _predictionEngine.Predict(input);

            var probabilities = new Dictionary<string, float>();
            for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
            {
                probabilities[_categoryLabels[i]] = MathF.Round(prediction.Score[i], 4);
            }

            return new PredictionResponse
            {
                PredictedCategory = prediction.Category,
                Probabilities = probabilities
            };
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketModelService _modelService;

    public TicketsController(TicketModelService modelService)
    {
        _modelService = modelService;
    }

    /// <summary>Trains the ML model using the CSV training data.</summary>
    [HttpPost("train")]
    public IActionResult Train()
    {
        _modelService.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    /// <summary>Returns evaluation metrics for the trained model.</summary>
    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        try
        {
            var metrics = _modelService.Evaluate();
            return Ok(metrics);
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        try
        {
            var result = _modelService.Predict(request);
            return Ok(result);
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }
}

