using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketModelService _modelService;

    public TicketsController(TicketModelService modelService)
    {
        _modelService = modelService;
    }

    /// <summary>Trains the ML model using the CSV training data.</summary>
    [HttpPost("train")]
    public IActionResult Train()
    {
        _modelService.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    /// <summary>Returns evaluation metrics for the trained model.</summary>
    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        try
        {
            var metrics = _modelService.Evaluate();
            return Ok(metrics);
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        try
        {
            var result = _modelService.Predict(request);
            return Ok(result);
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }
}

